PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?club ?clubLabel ?value WHERE {
  ?club wdt:P118 wd:Q19510 .
  ?club wdt:P31 wd:Q473976 .
  {
    ?club wdt:P8340 ?value
  } UNION {
    ?club wdt:P2139 ?value
  } UNION {
    ?club wdt:P2145 ?value
  }
  OPTIONAL {
    ?club rdfs:label ?clubLabel
    FILTER(LANG(?clubLabel) = "en")
  }
}
ORDER BY DESC(?value)
LIMIT 1
